def fetch(id) when is_bitstring(id) do
  case :ets.lookup(__MODULE__, id) do
    [{_, asset, _}] -> {:ok, asset}
    [] -> {:error, :not_found}
  end
end

def put(mutable, x, y, color)
def put({@mutable, {w, h, :g}, p}, x, y, color)
    when is_integer(x) and x >= 0 and x <= w and is_integer(y) and y >= 0 and y <= h do
  {:color_g, g} = Color.to_g(color)
  nif_put(p, y * w + x, g)
  {@mutable, {w, h, :g}, p}
end
def put({@mutable, {w, h, :ga}, p}, x, y, color)
    when is_integer(x) and x >= 0 and x <= w and is_integer(y) and y >= 0 and y <= h do
  {:color_ga, {g, a}} = Color.to_ga(color)
  nif_put(p, y * w + x, g, a)
  {@mutable, {w, h, :ga}, p}
end
def put({@mutable, {w, h, :rgb}, p}, x, y, color)
    when is_integer(x) and x >= 0 and x <= w and is_integer(y) and y >= 0 and y <= h do
  {:color_rgb, {r, g, b}} = Color.to_rgb(color)
  nif_put(p, y * w + x, r, g, b)
  {@mutable, {w, h, :rgb}, p}
end
def put({@mutable, {w, h, :rgba}, p}, x, y, color)
    when is_integer(x) and x >= 0 and x <= w and is_integer(y) and y >= 0 and y <= h do
  {:color_rgba, {r, g, b, a}} = Color.to_rgba(color)
  nif_put(p, y * w + x, r, g, b, a)
  {@mutable, {w, h, :rgba}, p}
end

def to_g(g) when is_uint8(g) do
  {@g, g}
end
def to_g({g, a}) when is_uint8(g) and is_uint8(a) do
  {@g, g}
end
def to_g({r, g, b}) when is_uint8(r) and is_uint8(g) and is_uint8(b) do
  {@g, do_rgb_to_g({r, g, b})}
end
def to_g({r, g, b, a}) when is_uint8(r) and is_uint8(g) and is_uint8(b) and is_uint8(a) do
  {@g, do_rgb_to_g({r, g, b})}
end
def to_g({@g, g}) do
  {@g, g}
end
def to_g({@ga, {g, _a}}) do
  {@g, g}
end
def to_g({@rgb, rgb}) do
  {@g, do_rgb_to_g(rgb)}
end
def to_g({@rgba, {r, g, b, _a}}) do
  {@g, do_rgb_to_g({r, g, b})}
end
def to_g({@hsv, hsv}) do
  g = hsv |> do_hsv_to_rgb() |> do_rgb_to_g()
  {@g, g}
end
def to_g({@hsl, hsl}) do
  g = hsl |> do_hsl_to_rgb() |> do_rgb_to_g()
  {@g, g}
end
def to_g(name) when is_atom(name) do
  {@g, name_to_rgb(name) |> do_rgb_to_g()}
end
def to_g({name, _a}) when is_atom(name) do
  {@g, name_to_rgb(name) |> do_rgb_to_g()}
end

