definition:
def arrival_substatus(%{
      predicted_schedule: %PredictedSchedule{
        prediction: %Prediction{schedule_relationship: relationship}
      }
    })
    when relationship in [:skipped, :cancelled] do
  relationship
end
def arrival_substatus(%{
      predicted_schedule: %PredictedSchedule{prediction: nil},
      route_type: :bus
    }) do
  :scheduled_sr_only
end
def arrival_substatus(%{route_type: route_type})
    when route_type not in [:commuter_rail, :ferry] do
  nil
end
def arrival_substatus(%{predicted_schedule: %PredictedSchedule{prediction: nil}}) do
  :scheduled
end
def arrival_substatus(%{
      predicted_schedule: %PredictedSchedule{prediction: %Prediction{status: status}}
    })
    when status != nil and status != "Delayed" do
  {:status, status |> String.split(" ") |> Enum.map_join(" ", &String.capitalize/1)}
end
def arrival_substatus(%{predicted_schedule: %PredictedSchedule{schedule: nil}}) do
  :on_time
end
def arrival_substatus(%{
      predicted_schedule: %PredictedSchedule{schedule: schedule, prediction: prediction}
    }) do
  scheduled_time = schedule.departure_time
  predicted_time = prediction.departure_time
  status = prediction.status

  cond do
    predicted_time == nil ->
      prediction.schedule_relationship

    DateTime.diff(predicted_time, scheduled_time, :second) <= -60 ->
      {:early_from, scheduled_time}

    DateTime.diff(predicted_time, scheduled_time, :second) >= 60 ->
      {:delayed_from, scheduled_time}

    status != nil ->
      {:status, status}

    true ->
      :on_time
  end
end

