end
def calculate_commuter_rail("1A", end_zone) do
  {:zone, end_zone}
end
def calculate_commuter_rail(start_zone, end_zone) do
  total_zones = abs(String.to_integer(start_zone) - String.to_integer(end_zone)) + 1
  {:interzone, "#{total_zones}"}
end

def get_nearby(position) do
  nearby_proposed_locations = by_lat_lon(position) || []

  nearby_proposed_locations
  |> Util.Distance.sort(position)
  |> Enum.slice(0, 50)
  |> Enum.map(fn loc ->
    lat_lon = {loc.latitude, loc.longitude}
    {loc, Util.Distance.haversine(lat_lon, position)}
  end)
end

