  0
end
def get_distance(home_stop_id, home_stop_distance_map, %InformedEntity{
      route: "Green" <> _,
      stop: %Stop{id: ie_stop_id}
    })
    when home_stop_id in @gl_trunk_stop_ids and ie_stop_id in @gl_eastbound_split_stops do
  Map.get(home_stop_distance_map, "place-lech", @default_distance)
end
