      route: "Green" <> _,
      stop: %{id: ie_stop_id}
    })
    when home_stop_id in @gl_trunk_stop_ids and ie_stop_id not in @gl_trunk_stop_ids do
  Map.get(home_stop_distance_map, "place-kencl", @default_distance)
end
def get_distance(_, home_stop_distance_map, %InformedEntity{stop: %{id: stop_id}}) do
  Map.get(home_stop_distance_map, stop_id, @default_distance)
