def eliminated_service_type(
      %__MODULE__{
        alert: %Alert{effect: effect},
        screen: %Screen{
          app_params: %Dup{primary_departures: %Departures{sections: primary_sections}}
        }
      } = t
    )
    when effect in [:shuttle, :station_closure, :suspension] do
  if LocalizedAlert.location(t) == :inside and not partial_station_closure?(t) and
       length(get_affected_lines(t)) == length(primary_sections) do
    :all
  else
    :some
  end
end
def eliminated_service_type(
      %__MODULE__{alert: %Alert{cause: :single_tracking, effect: :delay, severity: severity}} = t
    )
    when severity >= 5 do
  if LocalizedAlert.location(t) in [:inside, :boundary_downstream, :boundary_upstream] do
    :some
  else
    :none
  end
end
def eliminated_service_type(_other) do
  :none
end

